vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;



vec2 uv1 = (vUvOriginal-.5) * uAspect.xy;

vec2 uv6 = audioLow;

float z = 412*length(uv1) ;
vec2 d = -normalize(1/uv1);

vec2 rs = clamp(tan(q1*z+q30)*d,0,1);

if (q28 ==1) {rs *= cos(uv1.yx*1*q27) ;}

vUv += rs/40;

